1	'use strict';
2	// 태그 기반 분류 모듈 (갱신1 — 태그 모델).
3	//
4	// 철학: 고정 카테고리가 아니라 "태그 중심"으로 분류한다. PRESET은 추천(자동완성)용
5	//       프리셋일 뿐 강제 분류가 아니다. 사용자가 만든 커스텀 태그는 canonical 루트의
6	//       categories.json(배열)에 누적 저장한다.
7	//
8	// 정규화 규칙: 소문자화 → 허용문자 [a-z0-9가-힣-]만 남기고 나머지는 태그 경계로 →
9	//             빈값 제거 → 각 길이 ≤24로 자르기 → 중복 제거 → 최대 12개.
10	//
11	// 외부 의존성은 같은 cli/ 안의 paths(경로)·duplicate(jaccard)만 사용한다(둘 다 수정 금지).
12	
13	const fs = require('fs');
14	const path = require('path');
15	const paths = require('./paths');
16	const duplicate = require('./duplicate');
17	
18	// 추천용 프리셋(고정 분류 아님). 자동완성/제안 상단에 먼저 노출한다.
19	const PRESET = ['code', 'review', 'docs', 'infra', 'etc'];
20	
21	// 커스텀 태그를 저장하는 파일 경로 (canonical 루트 안, 모드별 분리는 paths가 처리).
22	function categoriesFile() {
23	  return path.join(paths.canonicalRoot(), 'categories.json');
24	}
25	
26	// 저장된 커스텀 태그 배열을 읽는다. 없거나 깨졌으면 [] 로 폴백(try/catch).
27	function loadCustom() {
28	  try {
29	    const raw = fs.readFileSync(categoriesFile(), 'utf8');
30	    const arr = JSON.parse(raw);
31	    return Array.isArray(arr) ? arr : [];
32	  } catch (e) {
33	    return [];
34	  }
35	}
36	
37	// 커스텀 태그 배열을 파일에 저장한다. 디렉토리 보장 + 실패해도 던지지 않게 try/catch.
38	function saveCustom(tags) {
39	  try {
40	    fs.mkdirSync(paths.canonicalRoot(), { recursive: true });
41	    fs.writeFileSync(categoriesFile(), JSON.stringify(tags, null, 2) + '\n');
42	    return true;
43	  } catch (e) {
44	    return false;
45	  }
46	}
47	
48	// 입력(문자열: 쉼표/공백 구분, 또는 배열)을 정규화한 태그 배열로 변환한다.
49	//   - 소문자화
50	//   - 허용문자 [a-z0-9가-힣-] 외는 태그 경계로 취급(쪼갬)
51	//   - 빈값 제거, 각 길이 ≤24, 중복 제거, 최대 12개
52	function normalizeTags(input) {
53	  let parts;
54	  if (Array.isArray(input)) {
55	    parts = input;
56	  } else if (input == null) {
57	    parts = [];
58	  } else {
59	    parts = [String(input)];
60	  }
61	
62	  const out = [];
63	  const seen = new Set();
64	  for (const part of parts) {
65	    // 허용문자 외(공백·쉼표·구두점 등)는 모두 경계로 → 여러 태그로 쪼갠다.
66	    const pieces = String(part)
67	      .toLowerCase()
68	      .split(/[^a-z0-9가-힣-]+/);
69	    for (let piece of pieces) {
70	      if (!piece) continue;
71	      // 경계 하이픈은 다듬는다(태그 중간 하이픈은 유지).
72	      piece = piece.replace(/^-+/, '').replace(/-+$/, '');
73	      if (!piece) continue;
74	      if (piece.length > 24) piece = piece.slice(0, 24);
75	      if (seen.has(piece)) continue;
76	      seen.add(piece);
77	      out.push(piece);
78	      if (out.length >= 12) return out;
79	    }
80	  }
81	  return out;
82	}
83	
84	// 추천 묶음을 만든다.
85	//   preset : 고정 프리셋
86	//   custom : 저장된 커스텀 태그
87	//   all    : preset + custom 합쳐 중복 제거(preset 먼저)
88	function suggestions() {
89	  const custom = loadCustom();
90	  const all = [];
91	  const seen = new Set();
92	  for (const t of PRESET.concat(custom)) {
93	    if (seen.has(t)) continue;
94	    seen.add(t);
95	    all.push(t);
96	  }
97	  return { preset: PRESET.slice(), custom, all };
98	}
99	
100	// 새 태그를 커스텀 목록에 등록한다.
101	//   - 입력을 normalize
102	//   - PRESET·기존 커스텀에 이미 있는 건 건너뛰고, 새 것만 append
103	//   - 저장 후 갱신된 커스텀 배열을 반환
104	function registerCustom(tags) {
105	  const incoming = normalizeTags(tags);
106	  const existing = loadCustom();
107	  const known = new Set(PRESET.concat(existing));
108	  let changed = false;
109	  for (const t of incoming) {
110	    if (known.has(t)) continue;
111	    known.add(t);
112	    existing.push(t);
113	    changed = true;
114	  }
115	  if (changed) saveCustom(existing);
116	  return existing;
117	}
118	
119	// 두 태그 집합의 유사도(0~1). duplicate.jaccard에 위임한다.
120	function tagMatch(aTags, bTags) {
121	  return duplicate.jaccard(new Set(normalizeTags(aTags)), new Set(normalizeTags(bTags)));
122	}
123	
124	// 태그 배열들의 출현 빈도 집계. [['a','b'],['a']] → { a: 2, b: 1 }
125	//   (각 항목은 normalize하지 않고 그대로 센다 — 이미 정규화된 태그가 들어온다는 전제)
126	function tagCounts(listOfTagArrays) {
127	  const counts = {};
128	  const list = Array.isArray(listOfTagArrays) ? listOfTagArrays : [];
129	  for (const arr of list) {
130	    if (!Array.isArray(arr)) continue;
131	    for (const t of arr) {
132	      counts[t] = (counts[t] || 0) + 1;
133	    }
134	  }
135	  return counts;
136	}
137	
138	module.exports = {
139	  PRESET,
140	  normalizeTags,
141	  suggestions,
142	  registerCustom,
143	  tagMatch,
144	  tagCounts,
145	};
146	
147	// 부작용 없는 검증 데모 (registerCustom은 파일을 쓰므로 호출하지 않는다).
148	if (require.main === module) {
149	  console.log('normalize:', normalizeTags('Code, Review code'));
150	  console.log('suggestions:', suggestions());
151	  console.log('match:', tagMatch(['code', 'review'], ['review']));
152	}
