1148	function storeApply({ id, resolution, newName, piAck }) {
1149	  let it = store.get(id);
1150	  if (!it) throw new Error('카탈로그 항목 없음: ' + id);
1151	
1152	  // PI 게이트 보강(스토어-R1): 외부(레지스트리) 출처 항목이 canonical로 들어가기 전
1153	  // 본문/neutral에 PI 검사를 적용한다(pull과 동일 패턴). 번들 항목은 신뢰된 번들이라 면제.
1154	  if (it.source_type === 'registry') {
1155	    const inspectText =
1156	      it.kind === 'skill'
