1159	    const pi = security.detectPI(inspectText);
1160	    if (pi.length > 0) {
1161	      if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(inspectText));
1162	      if (piAck === 'exclude') return { applied: false, reason: 'excluded', kind: it.kind, id };
1163	      if (piAck === 'mask') {
1164	        if (it.kind === 'skill') it = { ...it, body: security.mask(it.body || '') };
1165	        else it = { ...it, neutral: JSON.parse(security.mask(JSON.stringify(it.neutral || {}))) };
1166	      }
1167	      // 'proceed' → 그대로
1168	    }
1169	  }
1170	
1171	  if (it.kind === 'skill') {
1172	    let name = it.name;
1173	    if (canonical.skillExists(name) && !resolution) {
1174	      const cur = canonical.readSkill(name);
1175	      return { conflict: true, kind: 'skill', name, options: ['overwrite', 'skip', 'rename'],
1176	        diff: diff.lineDiff(cur.body, it.body || '') };
1177	    }
1178	    if (canonical.skillExists(name) && resolution === 'skip') return { applied: false, skipped: true, kind: 'skill', name };
1179	    if (canonical.skillExists(name) && resolution === 'rename') name = newName || name + '-2';
1180	    const tags = category.normalizeTags(it.tags || []);
1181	    canonical.writeSkill(name, it.body || '', { source_id: 'catalog', source_tool: 'bundled', official: it.official !== false, tags });
1182	    if (tags.length) category.registerCustom(tags);
1183	    gitCommit(`store install skill: ${name}`);
1184	    return { applied: true, kind: 'skill', name, results: skillPushAll({ name, apply: true }) };
1185	  }
1186	
1187	  if (it.kind === 'agent') {
1188	    const neutral = { ...it.neutral, tags: category.normalizeTags(it.tags || []) };
1189	    if (canonical.agentExists(neutral.id) && !resolution) {
1190	      const cur = canonical.readAgent(neutral.id);
1191	      return { conflict: true, kind: 'agent', id: neutral.id, options: ['overwrite', 'skip', 'rename'],
1192	        diff: diff.lineDiff(JSON.stringify(cur, null, 2), JSON.stringify(neutral, null, 2)) };
1193	    }
1194	    if (canonical.agentExists(neutral.id) && resolution === 'skip') return { applied: false, skipped: true, kind: 'agent', id: neutral.id };
1195	    if (canonical.agentExists(neutral.id) && resolution === 'rename') {
1196	      const nm = newName || neutral.name + '-2';
