30	// ── registries.json 읽기/쓰기 ────────────────────────────────────────
31	function load() {
32	  const file = paths.registriesFile();
33	  if (!fs.existsSync(file)) return { version: 1, registries: [], defaultsOverlay: {} };
34	  try {
35	    const data = JSON.parse(fs.readFileSync(file, 'utf8'));
36	    if (!data || !Array.isArray(data.registries)) return { version: 1, registries: [], defaultsOverlay: {} };
37	    return {
38	      version: data.version || 1,
39	      registries: data.registries,
40	      // 기본(official) 레지스트리의 revision/last_refreshed 오버레이(번들 원본은 정적).
41	      defaultsOverlay: (data.defaultsOverlay && typeof data.defaultsOverlay === 'object') ? data.defaultsOverlay : {},
42	    };
43	  } catch {
44	    return { version: 1, registries: [], defaultsOverlay: {} };
45	  }
46	}
