189	// name/description(+frontmatter tags/category)에서 skill-tags key 배열을 산출.
190	// 우선순위: (1) frontmatter tags/category 중 유효 key → (2) 휴리스틱 키워드.
191	// recommended-skills 오버라이드는 refresh()에서 repo+name 조인으로 별도 적용(최우선).
192	function categorize({ name, description, frontmatterTags, frontmatterCategory }) {
193	  const valid = validTagKeys();
194	  const out = [];
195	  const seen = new Set();
196	  const add = (k) => {
197	    const key = String(k).trim().toLowerCase();
198	    if (valid.has(key) && !seen.has(key)) {
199	      seen.add(key);
200	      out.push(key);
201	    }
202	  };
203	
204	  // (1) frontmatter tags/category 중 유효 key.
205	  const fmRaw = []
206	    .concat(Array.isArray(frontmatterTags) ? frontmatterTags : frontmatterTags ? [frontmatterTags] : [])
207	    .concat(Array.isArray(frontmatterCategory) ? frontmatterCategory : frontmatterCategory ? [frontmatterCategory] : []);
208	  for (const t of fmRaw) add(t);
209	  if (out.length) return out;
210	
211	  // (2) 휴리스틱: name+description 소문자에서 키워드/라벨을 "단어 경계"로 매칭.
212	  //     substring 매칭은 오탐이 많아(예: "plain"에 "ai") 단어 경계로 제한한다.
213	  const hay = (String(name || '') + ' ' + String(description || '')).toLowerCase();
214	  const hasWord = (needle) => {
215	    const n = String(needle).toLowerCase().trim();
216	    if (n.length < 2) return false;
217	    // needle이 여러 단어(공백/슬래시 포함)면 그대로 부분열, 단일 토큰이면 단어 경계.
218	    if (/[\s/]/.test(n)) return hay.includes(n);
219	    const re = new RegExp('(?:^|[^a-z0-9])' + n.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '(?:[^a-z0-9]|$)');
220	    return re.test(hay);
221	  };
222	  const defs = loadTagDefs();
223	  for (const def of defs) {
224	    const key = String(def.key);
225	    const labels = [key, def.en, def.ko].filter(Boolean);
226	    const kws = TAG_KEYWORDS[key] || [];
227	    const hit = labels.some((l) => hasWord(l)) || kws.some((kw) => hasWord(kw));
228	    if (hit) add(key);
229	  }
230	  return out;
231	}
