257	// 목록 — 기본(번들) + 사용자(registries.json) 병합.
258	//  - 기본은 official:true. 기본의 revision/last_refreshed는 registries.json의
259	//    defaultsOverlay[id]에서 오버레이(번들 원본은 정적 유지).
260	//  - 정규화 URL로 중복 제거: 사용자가 같은 url을 add했으면 기본 것을 유지(권장).
261	function list() {
262	  const user = load();
263	  const overlay = user.defaultsOverlay || {};
264	  const defaults = loadDefaults().map((d) => {
265	    const ov = overlay[d.id] || {};
266	    return {
267	      ...d,
268	      revision: ov.revision || null,
269	      last_refreshed: ov.last_refreshed || null,
270	    };
271	  });
272	
273	  const seen = new Set(defaults.map((d) => normalizeUrl(d.url)));
274	  const out = [...defaults];
275	  for (const r of user.registries) {
276	    if (r.official) continue; // registries.json엔 기본이 없어야 하지만, 방어적으로 건너뜀
277	    const key = normalizeUrl(r.url);
278	    if (seen.has(key)) continue; // 기본과 같은 url → 기본 유지, 사용자 것 스킵
279	    seen.add(key);
280	    out.push({ ...r, official: false });
281	  }
282	  return out;
283	}
