364	// default-registries.json의 publisher 원본(그룹 메타: totalSkills 등)만 뽑는다.
365	function loadDefaultsRaw() {
366	  const file = defaultRegistriesPath();
367	  const data = fs.existsSync(file) ? loadJsonSafe(file) : null;
368	  if (data && Array.isArray(data.publishers)) {
369	    return data.publishers.map((p) => ({
370	      slug: p.slug || slugify(String(p.id || p.name || '')),
371	      name: p.name || p.slug || '',
372	      totalSkills: typeof p.totalSkills === 'number' ? p.totalSkills : null,
373	    }));
374	  }
375	  return [];
376	}
