378	// 등록만 — 통신하지 않는다(refresh에서 clone).
379	function add(url, { name } = {}) {
380	  if (!url || typeof url !== 'string') throw new Error('레지스트리 URL이 필요합니다');
381	  const trimmed = url.trim();
382	  const id = slugify(trimmed);
383	  const reg = load();
384	  // 사용자 목록 중복
385	  if (reg.registries.some((r) => r.id === id)) {
386	    return { added: false, reason: 'duplicate', id };
387	  }
388	  // 기본(번들)과 같은 url이면 이미 목록에 노출되므로 추가 거부(중복).
389	  const key = normalizeUrl(trimmed);
390	  const dup = loadDefaults().find((d) => normalizeUrl(d.url) === key);
391	  if (dup) {
392	    return { added: false, reason: 'duplicate-default', id: dup.id };
393	  }
394	  const entry = {
395	    id,
396	    name: name || ownerRepoOf(trimmed),
397	    url: trimmed,
398	    added_at: new Date().toISOString(),
399	  };
400	  reg.registries.push(entry);
401	  save(reg);
402	  return { added: true, registry: entry };
403	}
404	
405	function remove(id) {
406	  // 기본(official) 레지스트리는 제거 거부 — 번들 정적이라 사용자가 지울 수 없다.
407	  if (loadDefaults().some((d) => d.id === id)) {
408	    return { removed: false, id, reason: 'default', message: '기본 레지스트리는 제거할 수 없습니다: ' + id };
409	  }
410	  const reg = load();
411	  const before = reg.registries.length;
412	  reg.registries = reg.registries.filter((r) => r.id !== id);
413	  if (reg.registries.length === before) return { removed: false, id };
414	  save(reg);
415	  // 캐시 파일도 정리(있으면).
416	  try {
417	    const cacheFile = registryItemsFile(id);
418	    if (fs.existsSync(cacheFile)) fs.unlinkSync(cacheFile);
419	  } catch {
420	    /* 캐시 삭제 실패는 치명적 아님 */
421	  }
422	  return { removed: true, id };
423	}
