(async () => {
  location.hash = 'skills';
  // wait for matrix + tags to load
  await new Promise(r => setTimeout(r, 1500));
  const bar = document.querySelector('#skills-filters');
  const pills = Array.from(bar.querySelectorAll('.filter-pill')).map(p => p.textContent.trim());
  const autoChips = Array.from(document.querySelectorAll('#skill-mx-rows .tok-chip.auto')).map(c => c.textContent.trim());
  const mainChips = Array.from(document.querySelectorAll('#skill-mx-rows .tok-chip:not(.auto)')).map(c => c.textContent.trim());
  return JSON.stringify({ pills, autoChips: autoChips.slice(0,8), mainChips: mainChips.slice(0,8) }, null, 1);
})()

(async () => {
  // click 코드 chip on skills
  const bar = document.querySelector('#skills-filters');
  const codeChip = Array.from(bar.querySelectorAll('.filter-pill')).find(p => p.textContent.trim().startsWith('코드'));
  codeChip.click();
  await new Promise(r => setTimeout(r, 400));
  // also add 리뷰 -> OR
  const bar2 = document.querySelector('#skills-filters');
  const reviewChip = Array.from(bar2.querySelectorAll('.filter-pill')).find(p => p.textContent.trim().startsWith('리뷰'));
  reviewChip.click();
  await new Promise(r => setTimeout(r, 400));
  const activeCount = document.querySelectorAll('#skills-filters .filter-pill.active').length;
  const clearChip = !!document.querySelector('#skills-filters .active-tag-chip');
  const visibleRows = document.querySelectorAll('#skill-mx-rows tr[data-mx-row]').length;
  const ctx = document.querySelector('#skill-mx-context') ? document.querySelector('#skill-mx-context').textContent.trim().slice(0,80) : '';
  return JSON.stringify({ activeCount, clearChip, visibleRows, ctx });
})()

(async () => {
  // clear tags via clear chip
  const clear = document.querySelector('#skills-filters .active-tag-chip');
  if (clear) clear.click();
  await new Promise(r => setTimeout(r, 300));
  // go to store
  location.hash = 'store';
  await new Promise(r => setTimeout(r, 1800));
  const bar = document.querySelector('#store-filters');
  const pills = Array.from(bar.querySelectorAll('.filter-pill')).map(p => p.textContent.trim());
  const catBar = document.querySelector('#store-cat-filters');
  const catPills = catBar ? Array.from(catBar.querySelectorAll('.filter-pill')).map(p=>p.textContent.trim()) : [];
  const cardChips = Array.from(document.querySelectorAll('#store-list .tok-chip')).slice(0,10).map(c=>c.textContent.trim());
  return JSON.stringify({ storeBarPills: pills.slice(0,14), catPillsSample: catPills.slice(0,4), cardChips }, null, 1);
})()

