(async () => {
  // clear store filter
  const clr = document.querySelector('#store-filters .active-tag-chip'); if (clr) clr.click();
  await new Promise(r=>setTimeout(r,300));
  // agents view
  location.hash = 'agents';
  await new Promise(r => setTimeout(r, 1500));
  const abar = document.querySelector('#agents-filters');
  const apills = Array.from(abar.querySelectorAll('.filter-pill')).map(p=>p.textContent.trim());
  const aAuto = Array.from(document.querySelectorAll('#agent-mx-rows .tok-chip.auto')).map(c=>c.textContent.trim());
  // publisher drilldown: open store, open a publisher card
  location.hash = 'store';
  await new Promise(r=>setTimeout(r,1500));
  const pubCard = document.querySelector('#store-default [data-pub-open]');
  let catPills = [];
  if (pubCard) {
    pubCard.click();
    await new Promise(r=>setTimeout(r,900));
    const cbar = document.querySelector('#store-cat-filters');
    catPills = cbar ? Array.from(cbar.querySelectorAll('.filter-pill')).map(p=>p.textContent.trim()) : ['(no cat bar)'];
  }
  return JSON.stringify({ agentPills: apills.slice(0,14), agentAutoChips: aAuto.slice(0,6), drilldownCatPills: catPills });
})()

(async () => {
  location.hash = 'skills';
  await new Promise(r=>setTimeout(r,1500));
  // switch to 전체 state filter to see all rows + sort
  const stateBar = document.querySelector('#skill-mx-state');
  const allFilter = Array.from(stateBar.querySelectorAll('.filter-pill')).find(p=>p.textContent.trim().startsWith('전체'));
  if (allFilter) allFilter.click();
  await new Promise(r=>setTimeout(r,400));
  const rows = Array.from(document.querySelectorAll('#skill-mx-rows tr[data-mx-row]'));
  const syncStates = rows.map(r=>{ const b=r.querySelector('.mx-sync .badge'); return b?b.textContent.trim():''; });
  // folder list present?
  const folders = Array.from(document.querySelectorAll('#skill-folder-list .mdf-item')).map(f=>f.querySelector('.mdf-label').textContent.trim());
  // search box
  const searchInput = document.querySelector('#skills [type=search], #skills input[placeholder*="검색"], #skill-mx-search');
  return JSON.stringify({ rowCount: rows.length, firstFiveStates: syncStates.slice(0,5), folders: folders.slice(0,4), hasSearch: !!searchInput });
})()
